    def score_thresh(self, task_type):
        # If we have fully explored the environment, set the matching threshold to 0.0
        # to go to the highest scoring instance
        if self.fully_explored[0]:
            return 0.0

        if task_type == "languagenav":
            return self.goal_policy_config.score_thresh_lang
        elif task_type == "imagenav":
            return self.goal_policy_config.score_thresh_image
        else:
            return 0.0
        
    def lagmemo_score(self, obs: Observations, detic_type: str = 'interest'):
        """Calculate the lagmemo score for the current observation and set flags accordingly."""
        img_thresh = 0.85
        txt_thresh = 0.3
        if detic_type == 'interest':
            img_thresh = 0.7
            txt_thresh = 0.23
        elif detic_type == 'common':
            img_thresh = 0.85
            txt_thresh = 0.3
        else:
            print(f"Unknown detic type: {detic_type}. Using default thresholds.")
        
        # 计算clip score
        match_score = 0
        task_type = obs.task_observations["tasks"][self.current_task_idx]['type']
        image_input = obs.rgb
        img_ref = np.asarray(obs.task_observations["tasks"][self.current_task_idx]['image'])

        if task_type == 'imagenav':
            match_score = self.mobileclip_score(obs.rgb, obs.task_observations["tasks"][self.current_task_idx]['image'], 'image')
        elif task_type == 'languagenav':
            match_score = self.mobileclip_score(obs.rgb, obs.task_observations['tasks'][self.current_task_idx]['description'], 'text')
            # image_input = obs.rgb
            # reference = obs.task_observations["tasks"][self.current_task_idx]['description']
            # match_score, seem_mask, seem_semantic_image = self.seem_model.img2txt_seem_seg(image_input, reference)
        elif task_type == 'objectnav':
            match_score = self.mobileclip_score(obs.rgb, obs.task_observations['tasks'][self.current_task_idx]['category'], 'text')
            # image_input = obs.rgb
            # reference = obs.task_observations["tasks"][self.current_task_idx]['category']
            # match_score, seem_mask, seem_semantic_image = self.seem_model.img2txt_seem_seg(image_input, reference)

        if match_score > txt_thresh and task_type in ['languagenav', 'objectnav']:
            self.stop_by_seem = True
            self.goal_vis_stage = 2
            
            if task_type == 'objectnav':
                reference = obs.task_observations["tasks"][self.current_task_idx]['category']
            elif task_type == 'languagenav':
                reference  = obs.task_observations["tasks"][self.current_task_idx]['description']
            _, seem_mask, seem_semantic_image = self.seem_model.img2txt_seem_seg(image_input, reference)

        elif task_type == 'imagenav' and match_score > img_thresh:
            self.stop_by_seem = True
            self.goal_vis_stage = 2
            # stop_by_clip = True
            reference = obs.task_observations["tasks"][self.current_task_idx]['category']
            _, goal_mask, image_output = self.seem_model.img2txt_seem_seg(image_input, reference)
            # cv2.imwrite("output_txt.png", image_output)
            # goal_mask = goal_mask if np.sum(goal_mask) != 0 else None
            if np.sum(goal_mask) != 0:
                goal_mask_mirrored = 1 - goal_mask.astype(np.uint8)
                goal_mask_mirrored = goal_mask_mirrored.astype(np.uint8)
                # 对seem_mask_mirrored进行膨胀操作, 去除边缘点和离散点
                kernel = np.ones((5, 5), np.uint8)
                goal_mask_mirrored = cv2.dilate(goal_mask_mirrored, kernel, iterations=2)
                goal_mask = 1 - goal_mask_mirrored
                goal_mask = goal_mask.astype(np.uint8)
            else:
                goal_mask = None

            _, seem_mask, seem_semantic_image = self.seem_model.img2img_seem_seg(image_input, img_ref, goal_mask)

            
            # masks, goal_imgs = self.seem_model.img2img_seem_seg(obs.rgb, text_seg=False)
            
            # best_score, best_idx = self.mobileclip_score_batch(goal_imgs, obs.rgb, 'image')

            # seem_mask = masks[best_idx]
            # seem_semantic_image = self.seem_model.get_seem_semantic_image(obs.rgb, seem_mask, match_score)
        
        else:
            seem_mask = np.zeros(2)
            seem_semantic_image = None
            
        return match_score, seem_mask, seem_semantic_image

